import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';

class MyWebView extends StatefulWidget {
  @override
  _MyWebViewState createState() => _MyWebViewState();
}

class _MyWebViewState extends State<MyWebView> {
  final Completer<WebViewController> _controller = Completer();
  
  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Web View Example')),
      body: WebView(
        initialUrlRequest: Uri.parse('https://www.yourwebsiteurl.com'),
        onWebViewCreated: (WebViewController webViewController) {
          _controller.complete(webViewController);

          webViewController.enableJavaScript(); // Enable JavaScript
          
          webViewController.addJavascriptChannels(JavascriptChannel({
            'name':'my_channel', // name of the channel (same in js code)
            'messageHandler': (JsMessage message) { 
              print('Web: ${message.message}');
              
              return JsResult("Success");
            },
          }));
        },
      ),
    );
  }
  
  void _sendToJS() async {
    String jsCode = "my_channel.postMessage('Hello from Dart!')";
    await _controller.future.then((WebViewController controller) {
      controller.evaluateJavascript(jsCode); // Call JS function
    });
  }
}